// Parse Lightspeed portfolio companies from Consider page HTML
const items = $input.all();
// Browserless /content returns HTML in data field or directly
const html = String(items[0]?.json?.data || items[0]?.json || '');
const results = [];
const seen = new Set();
const today = new Date().toISOString().split('T')[0];
const vcName = 'Lightspeed';

// Consider renders company cards with links and names
// Pattern 1: Look for company card links with company names
// Consider uses Next.js with JSON data embedded in script tags

// Try to extract from __NEXT_DATA__ script
const nextDataMatch = html.match(/<script[^>]*id="__NEXT_DATA__"[^>]*>([\s\S]*?)<\/script>/i);
if (nextDataMatch) {
  try {
    const nextData = JSON.parse(nextDataMatch[1]);
    // Navigate to companies data - try multiple known Consider paths
    const pageProps = nextData?.props?.pageProps || {};
    const companies = pageProps.companies || pageProps.data?.companies || pageProps.initialData?.companies || pageProps.dehydratedState?.queries?.[0]?.state?.data?.companies || pageProps.dehydratedState?.queries?.[0]?.state?.data?.results || [];

    for (const company of companies) {
      const name = company.name || company.companyName || '';
      if (!name || name.length < 2) continue;

      const key = name.toLowerCase().replace(/[^a-z0-9]/g, '');
      if (seen.has(key)) continue;
      seen.add(key);

      const domain = company.domain || '';
      const website = company.website?.url || (domain ? `https://${domain}` : '');
      const description = company.description || company.tagline || `${name} - Lightspeed portfolio company`;
      const stage = (company.stages || []).join(', ') || company.stage || '';
      const employees = company.staffCount || company.employeeCount || '';

      results.push({
        json: {
          'Company Name': name,
          'VC Firm': vcName,
          'Company Description': description,
          'Company URL': website,
          'Stage': stage,
          'Employee Count': employees,
          'Status': 'New',
          'First Seen Date': today,
          'Source': 'VC Portfolio'
        }
      });
    }
  } catch (e) {
    // JSON parse failed, fall through to HTML parsing
  }
}

// Fallback: Extract company slugs from HTML links and convert to names
if (results.length === 0) {
  const slugPattern = /href="\/companies\/([a-z0-9][a-z0-9-]{1,50}[a-z0-9])"/gi;
  const skipSlugs = new Set(['all', 'list', 'search', 'filter', 'page']);

  let match;
  while ((match = slugPattern.exec(html)) !== null) {
    const slug = match[1];
    if (skipSlugs.has(slug)) continue;

    // Convert slug to title case name: 'acme-corp' -> 'Acme Corp'
    const name = slug.split('-').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
    const key = slug.replace(/-/g, '');

    if (!seen.has(key) && key.length >= 2) {
      seen.add(key);
      results.push({
        json: {
          'Company Name': name,
          'VC Firm': vcName,
          'Company Description': `${name} - Lightspeed portfolio company`,
          'Company URL': '',
          'Status': 'New',
          'First Seen Date': today,
          'Source': 'VC Portfolio'
        }
      });
    }
  }
}

if (results.length === 0) {
  return [{ json: { _empty: true, _message: 'No companies found from Lightspeed', vcName, htmlLength: html.length, hasNextData: !!nextDataMatch, responseKeys: Object.keys(items[0]?.json || {}).slice(0, 5) } }];
}

return results;
